ect.keys(this.photos).length);\n\n       \n         //console.log(this.photos);\n        }); \n        /*\n        this.photos=[{\"id\":1,\"photo\":\"\\/uploads\\/events\\/event_1.jpg\"},{\"id\":2,\"photo\":\"\\/uploads\\/events\\/event_2.jpg\"},{\"id\":3,\"photo\":\"\\/uploads\\/events\\/event_3.jpg\"},{\"id\":4,\"photo\":\"\\/uploads\\/events\\/event_1.jpg\"},{\"id\":5,\"photo\":\"\\/uploads\\/events\\/event_2.jpg\"},{\"id\":6,\"photo\":\"\\/uploads\\/events\\/event_3.jpg\"}];\n        //this.showImage=1;*/\n       },\n       closeModal()\n    {\n     this.showImage=0;\n    },\n    getshowSlider(){\n      this.showImage=1;\n       \n    },\n\n      handleResize() \n      {\n     // this.window.width = window.innerWidth;\n      //this.window.height = window.innerHeight;\n        if(window.innerWidth<=980)\n        {\n            this.navigationEnabled=false;\n        }\n        else\n        {\n          this.navigationEnabled=true;\n        }\n      }\n    },\n  }\n</script>\n\n<style scoped>\n.VueCarousel-dot--active\n{\n  background-color: white! important;\n}\n   @media (max-width: 600px) {\n.VueCarousel-navigation-button{\n    display: none! important;\n  }\n}\n@media screen and (max-width: 660px) {\n  .VueCarousel-navigation-prev,\n  .VueCarousel-navigation-next{\n    display:none! important;\n  }\n}\n.VueCarousel-dot-button {\n    -webkit-appearance: none;\n    -moz-appearance: none;\n    appearance: none;\n    border: none;\n    background-color:black! important;\n    padding: 0;\n    border-radius: 100%;\n    outline: none;\n    cursor: pointer;\n}\n.tw-form-control-select {\n    display: block;\n    margin-top: 0.5rem;\n   /* -webkit-appearance: none;\n    -moz-appearance: none;\n    appearance: none;\n   width: 100%; */\n    background-color: #f7fafc;\n    border-width: 1px;\n    border-color: #edf2f7;\n    color: #000;\n    padding-top: 0.75rem;\n    padding-bottom: 0.75rem;\n    padding-left: 1rem;\n    padding-right: 1rem;\n    border-radius: 0.25rem;